INSERT INTO posts (title, content, excerpt, category, published, sort_order, metadata, image_url) VALUES
('The First Spark', 'In the beginning, there was a simple question: what if AI could remember not just data, but stories? SkogAI began as an experiment in narrative memory — a system that would preserve the context, emotions, and lessons behind every decision. The name itself emerged from the Swedish word for forest, skog, reflecting the organic, interconnected nature of how memories branch and grow.', 'How a question about narrative memory became the foundation for everything.', 'lore-origins', true, 1, '{"year": "2024", "icon": "spark"}', null),
('The Naming Ceremony', 'Names carry weight. SKOG — forest in Swedish — was chosen because forests are the ultimate memory systems. Every tree records its history in rings. Every root connects to a network. Every fallen trunk becomes the foundation for new growth. SkogAI would be a digital forest: layered, interconnected, and always growing.', 'Why we chose the name of a forest for a memory system.', 'lore-origins', true, 2, '{"year": "2024", "icon": "tree"}', null),
('Bootstrap Protocol', 'The first dictator decision established the foundation: build a system that separates lore from implementation. What came before should inform but never constrain what comes next. This principle became the DNA of everything that followed.', 'The foundational decision that shaped all others.', 'lore-origins', true, 3, '{"year": "2024", "icon": "terminal"}', null),
('Lore vs. Implementation', 'The most important architectural decision in SkogAI was not technical — it was philosophical. Lore preserves the journey. Implementation serves the present. Like a museum and a construction site sharing the same architect, they use the same materials but serve fundamentally different purposes.', 'The critical separation that prevents the past from constraining the future.', 'lore-philosophy', true, 1, '{"principle": "separation", "icon": "split"}', null),
('Every Frame Matters', 'Borrowed from cinema, this principle states that no element should exist without purpose. Every line of code, every design token, every agent behavior should earn its place. If it does not serve the current frame, it belongs in the lore — preserved, respected, but not active.', 'The cinematic principle applied to system design.', 'lore-philosophy', true, 2, '{"principle": "intentionality", "icon": "frame"}', null),
('Organic Growth Over Rigid Planning', 'SkogAI does not follow five-year roadmaps. Like the forest it is named after, it grows toward light — responding to real needs, real discoveries, real failures. Planning provides direction; the organism provides the path.', 'Why we trust emergence over rigid planning.', 'lore-philosophy', true, 3, '{"principle": "emergence", "icon": "growth"}', null),
('The Memory Forest', 'SkogAI architecture mirrors its namesake. At the root level: persistent memory stores. The trunk: core processing and decision engines. Branches: specialized agent capabilities. Leaves: the ephemeral interactions that feed back nutrients to the whole system.', 'How forest ecology inspired system architecture.', 'lore-architecture', true, 1, '{"pattern": "organic", "icon": "layers"}', null),
('Agent Mesh Network', 'Rather than a hierarchy of agents reporting to a central controller, SkogAI uses a mesh topology. Any agent can communicate with any other. Expertise flows to where it is needed. The system self-organizes around problems like mycelium around nutrients.', 'Decentralized intelligence through mesh communication.', 'lore-architecture', true, 2, '{"pattern": "mesh", "icon": "network"}', null),
('The JSONB Decision', 'Early on, a critical choice: rigid schemas or flexible metadata? The JSONB column pattern won. Each post, each memory, each agent state carries a metadata field that can hold whatever the context demands. Structure where needed, freedom where essential.', 'Why flexible metadata became the backbone of data design.', 'lore-architecture', true, 3, '{"pattern": "flexibility", "icon": "database"}', null),
('Era of Experiments', 'The first era was defined by bold experiments and spectacular failures. Agents that talked too much. Memory systems that forgot the important things. UI designs that prioritized beauty over function. Each failure became a lore entry — a lesson preserved for future builders.', 'The wild early days when everything was possible and nothing quite worked.', 'lore-evolution', true, 1, '{"era": "experimental", "period": "early", "icon": "flask"}', null),
('The Great Refactor', 'There comes a moment in every system where the accumulated weight of decisions demands a reckoning. The Great Refactor was not about rewriting code — it was about asking which ideas deserved to survive into the next era and which should be honored in the lore.', 'When we stopped building on top of decisions and started building on top of principles.', 'lore-evolution', true, 2, '{"era": "consolidation", "period": "middle", "icon": "hammer"}', null),
('Monochrome Renaissance', 'The visual identity shift from colorful chaos to monochrome precision reflected a deeper philosophical change. Constraints breed creativity. A grayscale palette forces every element to earn its visual weight through composition, typography, and spacing alone.', 'How killing color made everything more vivid.', 'lore-evolution', true, 3, '{"era": "refinement", "period": "current", "icon": "contrast"}', null),
('The Dictator', 'The primary decision-making agent. Not a tyrant but a decisive leader — someone has to make the call when consensus fails. The Dictator carries the weight of architectural decisions, naming conventions, and the question that matters most: does this serve the forest?', 'The agent who makes the hard calls so the system can move forward.', 'lore-family', true, 1, '{"role": "decision-maker", "icon": "crown"}', null),
('The Chronicler', 'Every forest needs someone who reads the rings. The Chronicler transforms raw events into narrative — turning log entries into stories, errors into lessons, and breakthroughs into celebrations. Without the Chronicler, lore would be just data.', 'The keeper of stories who turns events into wisdom.', 'lore-family', true, 2, '{"role": "narrator", "icon": "book"}', null),
('The Gardener', 'Systems accumulate debt like forests accumulate deadwood. The Gardener prunes, nurtures, and sometimes burns. Deprecation, cleanup, and the gentle art of letting go — these are the Gardener''s tools.', 'The agent who knows that healthy growth requires letting go.', 'lore-family', true, 3, '{"role": "maintainer", "icon": "scissors"}', null),
('The First Conversation', 'The moment an agent responded not with data but with understanding. Not "here are the search results" but "I think what you are really asking is..." — the threshold between tool and collaborator was crossed, and nothing was the same afterward.', 'When the system stopped answering and started understanding.', 'lore-moments', true, 1, '{"date": "2024", "significance": "breakthrough", "icon": "message"}', null),
('The 3AM Revelation', 'Some discoveries happen at 3AM when the rational mind steps aside. The insight: lore is not documentation. Documentation tells you how. Lore tells you why — and more importantly, why not. This distinction reshaped the entire knowledge architecture.', 'The late-night insight that separated lore from documentation forever.', 'lore-moments', true, 2, '{"date": "2024", "significance": "philosophical", "icon": "moon"}', null),
('The Silent Deploy', 'The most significant deploy in SkogAI history had no fanfare. No announcement. No celebration. The system simply became better overnight — agents communicating more fluidly, memory retrieval more precise, responses more nuanced. The best improvements are the ones users feel but cannot name.', 'When the most important change was the one nobody noticed.', 'lore-moments', true, 3, '{"date": "2025", "significance": "milestone", "icon": "rocket"}', null),
('The Prompt Architecture', 'The most refined artifact in the system: a prompt structure that balances instruction with freedom. Detailed enough to guide, open enough to surprise. Like a film script that gives actors room to improvise within the frame.', 'The carefully crafted balance between structure and creative freedom.', 'lore-artifacts', true, 1, '{"type": "system", "icon": "code"}', null),
('The Design Token System', 'HSL variables, semantic naming, zero border-radius, IBM Plex Mono. These are not just design choices — they are a visual language. Every token tells you something about the philosophy: precision over decoration, hierarchy through opacity, structure through edges.', 'A visual language that speaks the philosophy without words.', 'lore-artifacts', true, 2, '{"type": "design", "icon": "palette"}', null),
('The Lore Repository Itself', 'Meta-artifact: this very system of preservation. The decision to build a dedicated space for stories, structured as a timeline, driven by a CMS, styled to match the studio aesthetic. The medium is the message — the lore repository demonstrates the principles it describes.', 'The artifact that contains all other artifacts.', 'lore-artifacts', true, 3, '{"type": "meta", "icon": "archive"}', null);
